import io.grpc.*;
import io.grpc.stub.StreamObserver;
import java.io.*;
import java.nio.file.*;
import java.util.concurrent.atomic.AtomicLong;

public class FileTransferService extends FileTransferGrpc.FileTransferImplBase {
    private static final int MAX_MESSAGE_SIZE = 4 * 1024 * 1024; // 4MB
    private static final int MAX_FILE_SIZE = 100 * 1024 * 1024; // 100MB
    private static final AtomicLong totalBytesReceived = new AtomicLong(0);
    
    @Override
    public void uploadFile(StreamObserver<UploadResponse> responseObserver) {
        new StreamObserver<UploadRequest>() {
            private String fileName;
            private OutputStream fileOutputStream;
            private long totalBytes = 0;
            private long startTime = System.currentTimeMillis();
            
            @Override
            public void onNext(UploadRequest request) {
                try {
                    if (fileName == null) {
                        fileName = request.getFileName();
                        Path filePath = Paths.get("uploads", fileName);
                        Files.createDirectories(filePath.getParent());
                        fileOutputStream = Files.newOutputStream(filePath, StandardOpenOption.CREATE_NEW);
                    }
                    
                    if (request.hasData()) {
                        byte[] data = request.getData().toByteArray();
                        totalBytes += data.length;
                        
                        // Rate limiting and size checking
                        if (totalBytes > MAX_FILE_SIZE) {
                            throw new StatusRuntimeException(Status.RESOURCE_EXHAUSTED
                                .withDescription("File size limit exceeded"));
                        }
                        
                        // Update global counter for DoS protection
                        long currentTotal = totalBytesReceived.addAndGet(data.length);
                        if (currentTotal > 1000 * 1024 * 1024) { // 1GB limit
                            throw new StatusRuntimeException(Status.RESOURCE_EXHAUSTED
                                .withDescription("Server throughput limit exceeded"));
                        }
                        
                        fileOutputStream.write(data);
                    }
                    
                    if (request.getIsLast()) {
                        fileOutputStream.close();
                        long duration = System.currentTimeMillis() - startTime;
                        responseObserver.onNext(UploadResponse.newBuilder()
                            .setFileName(fileName)
                            .setFileSize(totalBytes)
                            .setDuration(duration)
                            .build());
                        responseObserver.onCompleted();
                    }
                } catch (Exception e) {
                    try {
                        if (fileOutputStream != null) {
                            fileOutputStream.close();
                        }
                    } catch (IOException ignored) {}
                    totalBytesReceived.addAndGet(-totalBytes);
                    responseObserver.onError(e);
                }
            }
            
            @Override
            public void onError(Throwable t) {
                try {
                    if (fileOutputStream != null) {
                        fileOutputStream.close();
                    }
                } catch (IOException ignored) {}
                totalBytesReceived.addAndGet(-totalBytes);
                responseObserver.onError(t);
            }
            
            @Override
            public void onCompleted() {
                responseObserver.onCompleted();
            }
        };
    }
    
    @Override
    public void downloadFile(DownloadRequest request, StreamObserver<DownloadResponse> responseObserver) {
        try {
            Path filePath = Paths.get("uploads", request.getFileName());
            if (!Files.exists(filePath)) {
                responseObserver.onError(Status.NOT_FOUND
                    .withDescription("File not found")
                    .asException());
                return;
            }
            
            long fileSize = Files.size(filePath);
            if (fileSize > MAX_FILE_SIZE) {
                responseObserver.onError(Status.RESOURCE_EXHAUSTED
                    .withDescription("File too large")
                    .asException());
                return;
            }
            
            try (InputStream fileInputStream = Files.newInputStream(filePath)) {
                byte[] buffer = new byte[MAX_MESSAGE_SIZE];
                int bytesRead;
                long totalBytes = 0;
                
                while ((bytesRead = fileInputStream.read(buffer)) != -1) {
                    totalBytes += bytesRead;
                    responseObserver.onNext(DownloadResponse.newBuilder()
                        .setData(ByteString.copyFrom(buffer, 0, bytesRead))
                        .build());
                }
                
                responseObserver.onCompleted();
            }
        } catch (Exception e) {
            responseObserver.onError(e);
        }
    }
    
    @Override
    public StreamObserver<TransferRequest> transferData(StreamObserver<TransferResponse> responseObserver) {
        return new StreamObserver<TransferRequest>() {
            private long totalBytes = 0;
            private long startTime = System.currentTimeMillis();
            
            @Override
            public void onNext(TransferRequest request) {
                try {
                    if (request.hasData()) {
                        byte[] data = request.getData().toByteArray();
                        totalBytes += data.length;
                        
                        if (totalBytes > MAX_FILE_SIZE) {
                            throw new StatusRuntimeException(Status.RESOURCE_EXHAUSTED
                                .withDescription("Data size limit exceeded"));
                        }
                        
                        long currentTotal = totalBytesReceived.addAndGet(data.length);
                        if (currentTotal > 1000 * 1024 * 1024) {
                            throw new StatusRuntimeException(Status.RESOURCE_EXHAUSTED
                                .withDescription("Server throughput limit exceeded"));
                        }
                        
                        responseObserver.onNext(TransferResponse.newBuilder()
                            .setAckBytes(data.length)
                            .setTotalBytes(totalBytes)
                            .build());
                    }
                } catch (Exception e) {
                    totalBytesReceived.addAndGet(-totalBytes);
                    responseObserver.onError(e);
                }
            }
            
            @Override
            public void onError(Throwable t) {
                totalBytesReceived.addAndGet(-totalBytes);
                responseObserver.onError(t);
            }
            
            @Override
            public void onCompleted() {
                long duration = System.currentTimeMillis() - startTime;
                responseObserver.onNext(TransferResponse.newBuilder()
                    .setTotalBytes(totalBytes)
                    .setDuration(duration)
                    .build());
                responseObserver.onCompleted();
            }
        };
    }
}

// Server setup
public class FileTransferServer {
    private final Server server;
    
    public FileTransferServer(int port) {
        this.server = ServerBuilder.forPort(port)
            .addService(new FileTransferService())
            .maxInboundMessageSize(100 * 1024 * 1024) // 100MB
            .maxInboundMetadataSize(1024 * 1024) // 1MB
            .build();
    }
    
    public void start() throws IOException {
        server.start();
        System.out.println("Server started on port " + server.getPort());
    }
    
    public void stop() {
        if (server != null) {
            server.shutdown();
        }
    }
    
    public static void main(String[] args) throws IOException {
        FileTransferServer server = new FileTransferServer(8080);
        server.start();
        Runtime.getRuntime().addShutdownHook(new Thread(() -> {
            System.out.println("Shutting down gRPC server...");
            server.stop();
            System.out.println("Server shut down.");
        }));
    }
}